"
<html>
<head>
  <style>
    body {
      font-family: Arial, sans-serif;
      background-color: #f2f2f2;
      margin: 0;
      padding: 0;
    }

    .container {
      width: 80%;
      margin: auto;
      background-color: #ffffff;
      border-radius: 10px;
      overflow: hidden;
    }

    .header {
      background-color: #c0392b;
      color: white;
      text-align: center;
      padding: 20px;
    }

    .content {
      padding: 20px;
      color: #333;
    }

    .box {
      margin-top: 20px;
      padding: 15px;
      background-color: #f8d7da;
      border-radius: 8px;
      color: #721c24;
    }

    .footer {
      text-align: center;
      font-size: 12px;
      color: red;
      padding: 15px;
    }
  </style>
</head>

<body>

<div class='container'>

  <div class='header'>
    <h2>🏦 Account Deactivated</h2>
  </div>

  <div class='content'>

    <p>
      Hi <b>" ++ upper(getVal(vars.FULLNAME)) ++ "</b>,
    </p>

    <p>
      Your bank account has been <b>deactivated successfully</b> in 
      <b>" ++ getVal(data.BANKNAME) ++ "</b>.
    </p>

    <div class='box'>
      <p><b>Account Number:</b> " ++ getVal(data.ACCOUNTNUMBER) ++ "</p>
    </div>

    <p>
      If this action was not performed by you, please contact customer support immediately.
    </p>

  </div>

  <div class='footer'>
    ⚠️ This is an automated email. Please do not reply.
  </div>

</div>

</body>
</html>
"]

