set-variable.value:
#[%dw 2.0
output text/plain

---
"
<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<title>Account Creation Confirmation</title>

<style>
body{
    margin:0;
    padding:0;
    background:#f4f6f9;
    font-family:Arial, Helvetica, sans-serif;
}

.container{
    max-width:700px;
    margin:30px auto;
    background:#ffffff;
    border-radius:12px;
    overflow:hidden;
    box-shadow:0px 4px 12px rgba(0,0,0,0.15);
}

.header{
    background:#004481;
    color:white;
    text-align:center;
    padding:25px;
}

.header h1{
    margin:0;
    font-size:28px;
}

.content{
    padding:30px;
    color:#333;
    line-height:1.8;
}

.success-box{
    background:#e8f5e9;
    border-left:5px solid #28a745;
    padding:15px;
    margin:20px 0;
    border-radius:5px;
}

.section-title{
    color:#004481;
    font-size:20px;
    font-weight:bold;
    margin-top:20px;
    margin-bottom:10px;
}

table{
    width:100%;
    border-collapse:collapse;
}

th{
    background:#004481;
    color:white;
    padding:12px;
    text-align:left;
}

td{
    border:1px solid #ddd;
    padding:12px;
}

tr:nth-child(even){
    background:#f8f9fa;
}

.account-number{
    color:#004481;
    font-size:20px;
    font-weight:bold;
}

.footer{
    text-align:center;
    padding:20px;
    font-size:12px;
    color:#666;
    background:#f8f9fa;
}

.note{
    margin-top:20px;
    background:#fff3cd;
    padding:15px;
    border-radius:5px;
    color:#856404;
}
</style>
</head>

<body>

<div class='container'>

    <div class='header'>
        <h1>🏦 Welcome to " ++ (vars.inputAttributes.bankName default "Real Bank") ++ "</h1>
    </div>

    <div class='content'>

        <p>
            Dear <b>" ++ upper(vars.inputPayload.FullName default "Customer") ++ "</b>,
        </p>

        <div class='success-box'>
            Your bank account has been created successfully.
        </div>

        <p>
            We are pleased to inform you that your account has been opened and is now active.
        </p>

        <div class='section-title'>
            Account Details
        </div>

        <table>

            <tr>
                <th>Field</th>
                <th>Details</th>
            </tr>

            <tr>
                <td>Account Number</td>
                <td class='account-number'>
                    " ++ (vars.accountNumber default "N/A") ++ "
                </td>
            </tr>

            <tr>
                <td>Customer Name</td>
                <td>" ++ (vars.inputPayload.FullName default "N/A") ++ "</td>
            </tr>

            <tr>
                <td>Mobile Number</td>
                <td>" ++ (vars.inputPayload.mobileNumber default "N/A") ++ "</td>
            </tr>

            <tr>
                <td>Email Address</td>
                <td>" ++ (vars.inputPayload.email default "N/A") ++ "</td>
            </tr>

            <tr>
                <td>Aadhaar Number</td>
                <td>" ++ (vars.inputAttributes.adharNumber default "N/A") ++ "</td>
            </tr>

            <tr>
                <td>Bank Name</td>
                <td>" ++ (vars.inputAttributes.bankName default "N/A") ++ "</td>
            </tr>

            <tr>
                <td>Address</td>
                <td>" ++ (vars.inputPayload.address default "N/A") ++ "</td>
            </tr>

            <tr>
                <td>Opening Balance</td>
                <td>₹0.00</td>
            </tr>

            <tr>
                <td>Account Status</td>
                <td>ACTIVE</td>
            </tr>

        </table>

        <div class='note'>
            Please keep your account number secure and do not share sensitive banking information with anyone.
        </div>

        <p>
            Thank you for choosing us. We look forward to serving your banking needs.
        </p>

    </div>

    <div class='footer'>
        © 2026 Real Bank | Secure Banking Services<br/>
        This is an automated email. Please do not reply.
    </div>

</div>

</body>
</html>
"]

